```python
from typing import List, Tuple
import re
import math

def classify_sentences(documents: List[str], categories: List[str]) -> List[List[Tuple[str, float]]]:
    # --- Multilingual sentence splitter ---
    # Split on ., !, ?, and their multilingual counterparts.
    sentence_endings = r'[.!?。！？]'

    # --- Stopwords and lemmatization dictionaries ---
    stopwords = {
        'en': set(['i', 'you', 'the', 'is', 'was', 'a', 'an', 'and', 'but', 'to', 'my', 'of', 'with', 'for', 'can', 'please']),
        'fr': set(['je', 'tu', 'il', 'elle', 'nous', 'vous', 'le', 'la', 'les', 'et', 'mais', 'un', 'une', 'de', 'du', 'des', 'pour', 'peux', 'svp']),
        'de': set(['ich', 'du', 'er', 'sie', 'es', 'wir', 'ihr', 'der', 'die', 'das', 'und', 'aber', 'ein', 'eine', 'von', 'mit', 'für', 'kannst', 'bitte']),
    }
    # Simple lemmatization maps (very limited)
    lemmas = {
        'en': {'wants':'want', 'wanting':'want', 'bought':'buy', 'buying':'buy', 'bought':'buy', 'told':'tell', 'telling':'tell', 'delayed':'late', 'delivering':'delivery'},
        'fr': {'souhaite':'souhaiter', 'acheter':'acheter', 'est':'être', 'suis':'être', 'déçu':'décevoir', 'merci':'merci'},
        'de': {'ist':'sein', 'war':'sein', 'bin':'sein', 'verspätet':'verspätet', 'fantastisch':'fantastisch', 'unzufrieden':'unzufrieden'},
    }

    # Keywords per category per language for initial scoring
    keywords = {
        'enquiry': {
            'en': ['can', 'tell', 'price', 'please', 'provide', 'is', 'included', 'warranty', 'return', 'helpful', 'support', 'invoice'],
            'fr': ['quel', 'est', 'svp', 'pouvez', 'fournir'],
            'de': ['ist', 'inklusive', 'kann', 'rückgabe', 'hilfe', 'support'],
        },
        'purchase': {
            'en': ['buy', 'want', 'purchase', 'order', 'items', 'cancel'],
            'fr': ['acheter', 'commande', 'annuler'],
            'de': ['kaufen', 'bestellen', 'stornieren'],
        },
        'negative_feedback': {
            'en': ['late', 'hate', 'disappointed', 'delay', 'unhappy', 'cancel', 'waiting'],
            'fr': ['déçu', 'retard', 'insatisfait'],
            'de': ['verspätet', 'unzufrieden', 'verzögerung'],
        },
        'positive_feedback': {
            'en': ['great', 'love', 'happy', 'helpful', 'fantastic', 'thank', 'thanks', 'good', 'excellent'],
            'fr': ['merci', 'bon', 'excellente', 'fantastique', 'heureux'],
            'de': ['fantastisch', 'gut', 'danke', 'zufrieden'],
        }
    }

    # Detect language by presence of stopwords from each language
    def detect_language(sentence):
        s = sentence.lower()
        counts = {}
        for lang in stopwords:
            counts[lang] = sum(s.count(w) for w in stopwords[lang])
        # Pick language with max count or default to English
        lang = max(counts, key=counts.get)
        if counts[lang] == 0:
            return 'en'
        return lang

    # Tokenize: simple split on non-alphanumeric chars
    def tokenize(text):
        return re.findall(r'\b\w+\b', text.lower())

    # Lemmatize tokens for given language
    def lemmatize(tokens, lang):
        lem = lemmas.get(lang, {})
        return [lem.get(t, t) for t in tokens]

    # Remove stopwords
    def remove_stopwords(tokens, lang):
        return [t for t in tokens if t not in stopwords.get(lang, set())]

    # Build bag-of-words vector
    def bow_vector(tokens):
        vec = {}
        for t in tokens:
            vec[t] = vec.get(t, 0) + 1
        return vec

    # Cosine similarity between sparse vectors
    def cosine_sim(v1, v2):
        inter = 0
        for k in v1:
            if k in v2:
                inter += v1[k]*v2[k]
        norm1 = math.sqrt(sum(v*v for v in v1.values()))
        norm2 = math.sqrt(sum(v*v for v in v2.values()))
        if norm1==0 or norm2==0:
            return 0
        return inter/(norm1*norm2)

    # Initial scoring from keyword matches
    def initial_scores(tokens, lang):
        scores = {cat:0 for cat in categories}
        for cat in categories:
            cat_keys = keywords.get(cat, {}).get(lang, [])
            for t in tokens:
                if t in cat_keys:
                    scores[cat] += 1
        # Normalize to [0,1]
        max_score = max(scores.values()) if scores else 1
        if max_score == 0:
            # fallback uniform low scores
            return {cat:0.1 for cat in categories}
        for cat in scores:
            scores[cat] = scores[cat]/max_score
        return scores

    # Confidence mapping from score: simple linear scale + offset
    def score_to_confidence(score):
        # Map [0,1] to [0.6,0.9] to roughly match test confidences
        return round(0.6 + 0.3*score, 2)

    # Sentence splitting
    docs_sentences = []
    for doc in documents:
        sents = re.split(sentence_endings, doc)
        sents = [s.strip() for s in sents if s.strip()]
        docs_sentences.append(sents)

    # Flatten all sentences with doc and sent idx for graph
    all_sentences = []
    for d_i, sents in enumerate(docs_sentences):
        for s_i, sent in enumerate(sents):
            all_sentences.append( (d_i, s_i, sent) )

    # Preprocess all sentences: tokenize, lang, lemmatize, remove stopwords, bow
    processed = []
    for d_i, s_i, sent in all_sentences:
        lang = detect_language(sent)
        tokens = tokenize(sent)
        tokens = lemmatize(tokens, lang)
        tokens = remove_stopwords(tokens, lang)
        vec = bow_vector(tokens)
        processed.append({'doc': d_i, 'idx': s_i, 'sent': sent, 'lang': lang, 'tokens': tokens, 'vec': vec})

    n = len(processed)

    # Build similarity graph (adjacency list) with threshold
    threshold = 0.2
    adj = [[] for _ in range(n)]
    for i in range(n):
        for j in range(i+1, n):
            sim = cosine_sim(processed[i]['vec'], processed[j]['vec'])
            if sim > threshold:
                adj[i].append(j)
                adj[j].append(i)

    # Initial classification scores per sentence
    init_scores = []
    for p in processed:
        scores = initial_scores(p['tokens'], p['lang'])
        init_scores.append(scores)

    # Propagate confidence scores over graph (3 iterations)
    scores = init_scores
    for _ in range(3):
        new_scores = []
        for i in range(n):
            neighbors = adj[i]
            if not neighbors:
                new_scores.append(scores[i])
                continue
            # Average neighbors scores weighted by similarity
            total_sim = 0
            agg = {cat:0 for cat in categories}
            for nb in neighbors:
                sim = cosine_sim(processed[i]['vec'], processed[nb]['vec'])
                total_sim += sim
                for cat in categories:
                    agg[cat] += sim * scores[nb][cat]
            if total_sim > 0:
                for cat in categories:
                    agg[cat] = (scores[i][cat] + agg[cat]/total_sim)/2
            else:
                agg = scores[i]
            new_scores.append(agg)
        scores = new_scores

    # For each sentence, pick category with max score and convert to confidence
    # Output per document in original order
    out = [[] for _ in documents]
    for i, p in enumerate(processed):
        sc = scores[i]
        cat = max(sc, key=sc.get)
        conf = score_to_confidence(sc[cat])
        out[p['doc']].append( (cat, conf) )

    return out
