        for i in range(n):
            neighbors = adj[i]
            if not neighbors:
                new_scores.append(scores[i])
                continue
            # Average neighbors scores weighted by similarity
            total_sim = 0
            agg = {cat:0 for cat in categories}
            for nb in neighbors:
                sim = cosine_sim(processed[i]['vec'], processed[nb]['vec'])
                total_sim += sim
                for cat in categories:
                    agg[cat] += sim * scores[nb][cat]
            if total_sim > 0:
